mapper.select:
SELECT t1.ID trustId, t1.SHIPVOYAGE_ID, t1.SHIPVOYAGE_ITEM_ID, t1.COMPANY_ID, t1.COMPANY_NAME, t1.TRUST_NO, t1.PROCESS_NAME, t1.PROCESS_CODE, t2.BERTH_TIME, t2.SHIP_NAME shipvoyageName, CONCAT(CONCAT(T2.SHIP_NAME, '_') , TDSI.VOYAGE) as "shipvoyagesName", t1.TRADE_TYPE, t2.LOAD_UNLOAD, t2.LOAD_UNLOAD, t2.BERTH_TIME, DECODE ( t1.STATUS, '30', '已发布', '40', '作业中', '50', '已核销' ) STATUS FROM T_BUS_TRUST t1 LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TDSI.ID = t1.SHIPVOYAGE_ITEM_ID LEFT JOIN T_DIS_SHIPVOYAGE t2 ON TDSI.SHIPVOYAGE_ID = t2.ID WHERE 1=1
AND t1.PROCESS_CODE= #{processCode}
AND t2.SHIP_NAME LIKE #{shipvoyageName}
and t1.status = '50'
and (t1.status = '30' or t1.STATUS='40')

mapper.update:
update T_PRD_WATER_ELECTRICITY
SHIPVOYAGE_ID = #{shipvoyageId}, SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}, PROCESS_CODE = #{processCode}, PROCESS_NAME = #{processName}, START_NUMBER = #{startNumber}, END_NUMBER = #{endNumber}, QUANTITY = #{quantity}, START_TIME = #{workTime}, REMARK = #{remark}, UPDATE_BY = #{loginUserId}, UPDATE_BY_NAME = #{loginUserName}, UPDATE_TIME = #{now}, TRUST_ID = #{trustId}, END_TIME = #{workTimeEnd}, POWER_ON_USER_ID = #{powerOnUserId,jdbcType=BIGINT}, POWER_ON_USER_NAME = #{powerOnUserName,jdbcType=VARCHAR}, POWER_DIS_USER_ID = #{powerDisUserId,jdbcType=BIGINT}, POWER_DIS_USER_NAME = #{powerOnUserName,jdbcType=VARCHAR}, MAGNI = #{ratio,jdbcType=BIGINT}
where ID = #{id}

update T_BUS_TRUST
set status = 40,
    UPDATE_BY = #{loginUserId},
    UPDATE_BY_NAME = #{loginUserName},
    UPDATE_TIME = #{now}
where ID = #{trustId}
